// Frontend wiring: calls the bound Go App methods (from guiapi) over Wails.
//
// The imports below resolve to bindings GENERATED by the Wails toolchain into
// frontend/wailsjs/ on `wails dev` / `wails generate module`. They do not exist
// until then (the directory is gitignored), so type-checking this file requires
// running Wails once.
import "./style.css";
import {
  DNSStatus,
  Backend,
  ListServices,
  SetDNS,
  ClearDNS,
  FlushDNS,
  ListHosts,
  ListSystemHosts,
  AddHost,
  RemoveHost,
  ListProfiles,
  ApplyProfile,
  SaveProfile,
  DeleteProfile,
  HelperStatus,
} from "../wailsjs/go/guiapi/App";
import { hosts, service } from "../wailsjs/go/models";

// Mirrors guiapi.ServiceDNS. Typed locally so the read path doesn't depend on
// the generated model namespace.
interface ServiceDNS {
  service: string;
  servers: string[];
  dhcp: boolean;
  primary: boolean;
}

// Mirrors service.Profile (read path); writes use the generated service.Profile.
interface ProfileInfo {
  name: string;
  description: string;
  servers: string[];
  dhcp: boolean;
}

type View = "dns" | "profiles" | "hosts" | "settings";
type Theme = "light" | "dark" | "system";

// --- Theme ---

const THEME_KEY = "dnsctl.theme";

function getTheme(): Theme {
  const t = localStorage.getItem(THEME_KEY);
  return t === "light" || t === "dark" || t === "system" ? t : "system";
}

function applyTheme(theme: Theme): void {
  const root = document.documentElement;
  if (theme === "system") root.removeAttribute("data-theme");
  else root.setAttribute("data-theme", theme);
  localStorage.setItem(THEME_KEY, theme);
}

// --- Font ---

type Font = "system" | "rounded" | "mono";

const FONT_KEY = "dnsctl.font";

// CSS font stacks per option, used both for the live --ui-font and the preview
// tiles. Keep in sync with [data-font] rules in style.css.
const FONT_STACKS: Record<Font, string> = {
  system: `-apple-system, BlinkMacSystemFont, "SF Pro Text", "Helvetica Neue", sans-serif`,
  rounded: `ui-rounded, "SF Pro Rounded", -apple-system, system-ui, sans-serif`,
  mono: `ui-monospace, "SF Mono", Menlo, Monaco, monospace`,
};

function getFont(): Font {
  const f = localStorage.getItem(FONT_KEY);
  return f === "rounded" || f === "mono" ? f : "system";
}

function applyFont(font: Font): void {
  const root = document.documentElement;
  if (font === "system") root.removeAttribute("data-font");
  else root.setAttribute("data-font", font);
  localStorage.setItem(FONT_KEY, font);
}

// Apply before rendering to avoid a flash of the wrong palette/font.
applyTheme(getTheme());
applyFont(getFont());

// --- Boolean preferences ---

const CONFIRM_KEY = "dnsctl.confirmRemove";
const SHOWSYS_KEY = "dnsctl.showSystem";

const getConfirmRemove = (): boolean => localStorage.getItem(CONFIRM_KEY) !== "false"; // default on
const setConfirmRemove = (v: boolean): void => localStorage.setItem(CONFIRM_KEY, String(v));
const getShowSystem = (): boolean => localStorage.getItem(SHOWSYS_KEY) === "true"; // default off
const setShowSystem = (v: boolean): void => localStorage.setItem(SHOWSYS_KEY, String(v));

// confirmDialog shows an in-app modal (window.confirm isn't reliable in the
// webview) and resolves true if the user confirms.
function confirmDialog(title: string, message: string): Promise<boolean> {
  return new Promise((resolve) => {
    const overlay = document.createElement("div");
    overlay.className = "modal-overlay";
    overlay.innerHTML = `
      <div class="modal">
        <h2>${title}</h2>
        <p>${message}</p>
        <div class="modal-actions">
          <button class="btn" data-act="cancel">Cancel</button>
          <button class="btn destructive" data-act="ok">Remove</button>
        </div>
      </div>`;
    document.body.appendChild(overlay);
    const close = (v: boolean) => {
      overlay.remove();
      resolve(v);
    };
    overlay.querySelector('[data-act="cancel"]')!.addEventListener("click", () => close(false));
    overlay.querySelector('[data-act="ok"]')!.addEventListener("click", () => close(true));
    overlay.addEventListener("click", (e) => {
      if (e.target === overlay) close(false);
    });
  });
}

const GEAR_SVG = `<svg viewBox="0 0 16 16" fill="currentColor" aria-hidden="true"><path d="M8 5a3 3 0 100 6 3 3 0 000-6zm0 1.5a1.5 1.5 0 110 3 1.5 1.5 0 010-3z"/><path d="M6.94 1.5a.9.9 0 01.9-.75h.32a.9.9 0 01.9.75l.12.74a4.6 4.6 0 011.06.61l.7-.28a.9.9 0 011.1.39l.16.28a.9.9 0 01-.2 1.15l-.58.47c.05.36.05.72 0 1.08l.58.47a.9.9 0 01.2 1.15l-.16.28a.9.9 0 01-1.1.39l-.7-.28c-.33.26-.69.46-1.06.61l-.12.74a.9.9 0 01-.9.75h-.32a.9.9 0 01-.9-.75l-.12-.74a4.6 4.6 0 01-1.06-.61l-.7.28a.9.9 0 01-1.1-.39l-.16-.28a.9.9 0 01.2-1.15l.58-.47a4.7 4.7 0 010-1.08l-.58-.47a.9.9 0 01-.2-1.15l.16-.28a.9.9 0 011.1-.39l.7.28c.33-.26.69-.46 1.06-.61l.12-.74z"/></svg>`;

const app = document.querySelector<HTMLDivElement>("#app")!;
app.innerHTML = `
  <aside class="sidebar">
    <div class="sidebar-title">dnsctl</div>
    <button class="nav-item" data-view="dns">DNS Status</button>
    <button class="nav-item" data-view="profiles">Profiles</button>
    <button class="nav-item" data-view="hosts">Hosts</button>
    <div class="sidebar-spacer"></div>
    <button class="nav-item icon-item" data-view="settings" title="Settings">${GEAR_SVG}Settings</button>
  </aside>
  <main class="content" id="content"></main>
`;

const content = document.querySelector<HTMLElement>("#content")!;
const navItems = Array.from(document.querySelectorAll<HTMLButtonElement>(".nav-item"));

function escapeHtml(s: string): string {
  return s.replace(/[&<>"]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" })[c]!);
}

function setView(view: View): void {
  navItems.forEach((n) => n.classList.toggle("active", n.dataset.view === view));
  if (view === "dns") void renderDNS();
  else if (view === "profiles") void renderProfiles();
  else if (view === "hosts") void renderHosts();
  else renderSettings();
}
navItems.forEach((n) => n.addEventListener("click", () => setView(n.dataset.view as View)));

// --- DNS Status (editable) ---

// Service currently in inline-edit mode ("" = none), so a re-render keeps the
// open editor.
let editingService = "";

async function renderDNS(): Promise<void> {
  content.innerHTML = `<h1>DNS Status</h1><p class="subtitle">Loading…</p>`;
  try {
    const backend = await Backend();
    const rows = (await DNSStatus()) as unknown as ServiceDNS[];
    content.innerHTML = `
      <h1>DNS Status</h1>
      <p class="subtitle">Set each service's DNS servers via ${escapeHtml(backend)}</p>
      <div class="toolbar">
        <button class="btn" id="dns-flush">Flush DNS cache</button>
      </div>
      <p class="error" id="dns-error"></p>
      <div class="card" id="dns-list"></div>`;
    document.querySelector<HTMLButtonElement>("#dns-flush")!.addEventListener("click", async () => {
      const errEl = document.querySelector<HTMLParagraphElement>("#dns-error")!;
      errEl.textContent = "";
      try {
        await FlushDNS();
        flashButton("#dns-flush", "Flushed ✓");
      } catch (err) {
        errEl.textContent = String(err);
      }
    });
    renderDNSRows(rows);
  } catch (err) {
    content.innerHTML = `<h1>DNS Status</h1><p class="error">${escapeHtml(String(err))}</p>`;
  }
}

function renderDNSRows(rows: ServiceDNS[]): void {
  const listEl = document.querySelector<HTMLDivElement>("#dns-list")!;
  if (!rows.length) {
    listEl.innerHTML = `<div class="empty">No network services found.</div>`;
    return;
  }
  listEl.innerHTML = "";
  for (const r of rows) {
    listEl.appendChild(r.service === editingService ? dnsEditRow(r) : dnsViewRow(r));
  }
}

function dnsViewRow(r: ServiceDNS): HTMLElement {
  const row = document.createElement("div");
  row.className = "row";
  row.innerHTML = `
    <span class="primary">${escapeHtml(r.service)}</span>
    ${r.primary ? `<span class="badge active">Active</span>` : ``}
    <span class="spacer"></span>
    ${
      r.dhcp
        ? `<span class="badge">Automatic (DHCP)</span>`
        : `<span class="secondary mono">${r.servers.map(escapeHtml).join(", ")}</span>`
    }`;
  const edit = document.createElement("button");
  edit.className = "btn";
  edit.textContent = "Edit";
  edit.addEventListener("click", () => {
    editingService = r.service;
    void reloadDNS();
  });
  row.appendChild(edit);
  return row;
}

function dnsEditRow(r: ServiceDNS): HTMLElement {
  const row = document.createElement("div");
  row.className = "row";
  row.innerHTML = `
    <span class="primary">${escapeHtml(r.service)}</span>
    <span class="spacer"></span>
    <input class="dns-servers" value="${escapeHtml(r.servers.join(", "))}" placeholder="1.1.1.1, 1.0.0.1" />`;
  const input = row.querySelector<HTMLInputElement>(".dns-servers")!;

  const save = document.createElement("button");
  save.className = "btn primary";
  save.textContent = "Save";
  save.addEventListener("click", () => void applyServers(r.service, input.value));

  const dhcp = document.createElement("button");
  dhcp.className = "btn";
  dhcp.textContent = "Use DHCP";
  dhcp.addEventListener("click", () => void revertDHCP(r.service));

  const cancel = document.createElement("button");
  cancel.className = "btn";
  cancel.textContent = "Cancel";
  cancel.addEventListener("click", () => {
    editingService = "";
    void reloadDNS();
  });

  row.append(save, dhcp, cancel);
  return row;
}

async function applyServers(svc: string, raw: string): Promise<void> {
  const errEl = document.querySelector<HTMLParagraphElement>("#dns-error")!;
  errEl.textContent = "";
  const servers = raw.split(",").map((s) => s.trim()).filter(Boolean);
  if (!servers.length) {
    errEl.textContent = "Enter at least one server, or use DHCP.";
    return;
  }
  try {
    await SetDNS(svc, servers);
    editingService = "";
    await reloadDNS();
  } catch (err) {
    errEl.textContent = String(err);
  }
}

async function revertDHCP(svc: string): Promise<void> {
  const errEl = document.querySelector<HTMLParagraphElement>("#dns-error")!;
  errEl.textContent = "";
  try {
    await ClearDNS(svc);
    editingService = "";
    await reloadDNS();
  } catch (err) {
    errEl.textContent = String(err);
  }
}

// reloadDNS refreshes just the service rows (cheaper than a full re-render and
// preserves the toolbar/error elements).
async function reloadDNS(): Promise<void> {
  const rows = (await DNSStatus()) as unknown as ServiceDNS[];
  renderDNSRows(rows);
}

// flashButton briefly shows confirmation text on a button, then restores it.
function flashButton(selector: string, text: string): void {
  const btn = document.querySelector<HTMLButtonElement>(selector);
  if (!btn) return;
  const orig = btn.textContent;
  btn.textContent = text;
  btn.disabled = true;
  setTimeout(() => {
    btn.textContent = orig;
    btn.disabled = false;
  }, 1200);
}

// --- Profiles (editable) ---

async function renderProfiles(): Promise<void> {
  content.innerHTML = `<h1>Profiles</h1><p class="subtitle">Loading…</p>`;
  let services: string[] = [];
  try {
    services = await ListServices();
  } catch {
    // No DNS backend: profiles can still be listed/edited, just not applied.
  }
  const serviceOptions = services.map((s) => `<option value="${escapeHtml(s)}">${escapeHtml(s)}</option>`).join("");

  content.innerHTML = `
    <h1>Profiles</h1>
    <p class="subtitle">Named DNS server sets you can apply to a network service</p>
    <div class="toolbar">
      <input id="p-name" placeholder="name (cloudflare)" />
      <input id="p-servers" placeholder="servers (1.1.1.1, 1.0.0.1)" />
      <input id="p-desc" placeholder="description (optional)" />
      <label class="inline-check"><input type="checkbox" id="p-dhcp" /> DHCP</label>
      <button class="btn primary" id="p-save">Add</button>
    </div>
    <p class="error" id="p-error"></p>
    ${
      services.length
        ? `<div class="toolbar"><span class="secondary">Apply to:</span>
             <select id="p-target">${serviceOptions}</select></div>`
        : `<p class="subtitle">No DNS backend available — profiles can be edited but not applied.</p>`
    }
    <div class="card" id="p-list"></div>`;

  const dhcpBox = document.querySelector<HTMLInputElement>("#p-dhcp")!;
  const serversInput = document.querySelector<HTMLInputElement>("#p-servers")!;
  dhcpBox.addEventListener("change", () => {
    serversInput.disabled = dhcpBox.checked;
    if (dhcpBox.checked) serversInput.value = "";
  });
  document.querySelector<HTMLButtonElement>("#p-save")!.addEventListener("click", () => void saveProfile());

  await refreshProfiles(services.length > 0);
}

async function refreshProfiles(canApply: boolean): Promise<void> {
  const listEl = document.querySelector<HTMLDivElement>("#p-list")!;
  const profiles = (await ListProfiles()) as unknown as ProfileInfo[];
  if (!profiles.length) {
    listEl.innerHTML = `<div class="empty">No profiles yet. Add one above.</div>`;
    return;
  }
  listEl.innerHTML = "";
  for (const p of profiles) {
    const row = document.createElement("div");
    row.className = "row";
    const servers = p.dhcp ? "DHCP" : p.servers.join(", ");
    row.innerHTML = `
      <span class="primary">${escapeHtml(p.name)}</span>
      <span class="secondary mono">${escapeHtml(servers)}</span>
      ${p.description ? `<span class="badge">${escapeHtml(p.description)}</span>` : ``}
      <span class="spacer"></span>`;

    if (canApply) {
      const apply = document.createElement("button");
      apply.className = "btn primary";
      apply.textContent = "Apply";
      apply.addEventListener("click", () => void applyProfileToTarget(p.name));
      row.appendChild(apply);
    }

    const edit = document.createElement("button");
    edit.className = "btn";
    edit.textContent = "Edit";
    edit.addEventListener("click", () => fillProfileForm(p));
    row.appendChild(edit);

    const del = document.createElement("button");
    del.className = "btn danger";
    del.textContent = "Remove";
    del.addEventListener("click", async () => {
      if (getConfirmRemove()) {
        const ok = await confirmDialog("Remove profile", `Delete the profile "${p.name}"?`);
        if (!ok) return;
      }
      await DeleteProfile(p.name);
      await refreshProfiles(canApply);
    });
    row.appendChild(del);

    listEl.appendChild(row);
  }
}

function fillProfileForm(p: ProfileInfo): void {
  document.querySelector<HTMLInputElement>("#p-name")!.value = p.name;
  const serversInput = document.querySelector<HTMLInputElement>("#p-servers")!;
  const dhcpBox = document.querySelector<HTMLInputElement>("#p-dhcp")!;
  dhcpBox.checked = p.dhcp;
  serversInput.disabled = p.dhcp;
  serversInput.value = p.dhcp ? "" : p.servers.join(", ");
  document.querySelector<HTMLInputElement>("#p-desc")!.value = p.description;
  document.querySelector<HTMLButtonElement>("#p-save")!.textContent = "Save";
}

async function saveProfile(): Promise<void> {
  const errEl = document.querySelector<HTMLParagraphElement>("#p-error")!;
  errEl.textContent = "";
  const name = document.querySelector<HTMLInputElement>("#p-name")!.value.trim();
  const dhcp = document.querySelector<HTMLInputElement>("#p-dhcp")!.checked;
  const servers = document
    .querySelector<HTMLInputElement>("#p-servers")!
    .value.split(",")
    .map((s) => s.trim())
    .filter(Boolean);
  const description = document.querySelector<HTMLInputElement>("#p-desc")!.value.trim();

  if (!name) {
    errEl.textContent = "A profile name is required.";
    return;
  }
  if (!dhcp && !servers.length) {
    errEl.textContent = "Add at least one server, or check DHCP.";
    return;
  }
  try {
    await SaveProfile(new service.Profile({ name, description, servers, dhcp }));
    // Reset the form.
    document.querySelector<HTMLInputElement>("#p-name")!.value = "";
    document.querySelector<HTMLInputElement>("#p-servers")!.value = "";
    document.querySelector<HTMLInputElement>("#p-desc")!.value = "";
    const dhcpBox = document.querySelector<HTMLInputElement>("#p-dhcp")!;
    dhcpBox.checked = false;
    document.querySelector<HTMLInputElement>("#p-servers")!.disabled = false;
    document.querySelector<HTMLButtonElement>("#p-save")!.textContent = "Add";
    await refreshProfiles(!!document.querySelector("#p-target"));
  } catch (err) {
    errEl.textContent = String(err);
  }
}

async function applyProfileToTarget(name: string): Promise<void> {
  const errEl = document.querySelector<HTMLParagraphElement>("#p-error")!;
  errEl.textContent = "";
  const target = document.querySelector<HTMLSelectElement>("#p-target");
  const svc = target ? target.value : "";
  try {
    await ApplyProfile(name, svc);
    errEl.textContent = "";
    flashMessage(`Applied "${name}"${svc ? ` to ${svc}` : ""}.`);
  } catch (err) {
    errEl.textContent = String(err);
  }
}

// flashMessage shows a transient success note in the profiles error slot
// (reused as a status line).
function flashMessage(text: string): void {
  const errEl = document.querySelector<HTMLParagraphElement>("#p-error");
  if (!errEl) return;
  errEl.textContent = text;
  errEl.classList.add("ok");
  setTimeout(() => {
    errEl.textContent = "";
    errEl.classList.remove("ok");
  }, 2000);
}

// --- Hosts (editable) ---

async function renderHosts(): Promise<void> {
  content.innerHTML = `
    <h1>Hosts</h1>
    <p class="subtitle">dnsctl-managed entries in /etc/hosts</p>
    <div class="toolbar">
      <input id="h-hostname" placeholder="hostname (app.local)" />
      <input id="h-ip" placeholder="IP (127.0.0.1)" />
      <input id="h-comment" placeholder="comment (optional)" />
      <button class="btn primary" id="h-add">Add</button>
    </div>
    <p class="error" id="h-error"></p>
    <div class="card" id="h-list"></div>
    <div id="sys-section"></div>`;
  document.querySelector<HTMLButtonElement>("#h-add")!.addEventListener("click", () => void addHost());
  await refreshHosts();
  await renderSystemSection();
}

// renderSystemSection shows the read-only, unmanaged /etc/hosts entries when
// the "Show system entries" preference is on.
async function renderSystemSection(): Promise<void> {
  const el = document.querySelector<HTMLDivElement>("#sys-section");
  if (!el) return;
  if (!getShowSystem()) {
    el.innerHTML = "";
    return;
  }
  const sys = await ListSystemHosts();
  const rows = sys
    .map(
      (e) => `
      <div class="row">
        <span class="primary mono">${escapeHtml(e.hostname)}</span>
        <span class="secondary mono">${escapeHtml(e.ip)}</span>
        <span class="spacer"></span>
      </div>`
    )
    .join("");
  el.innerHTML = `
    <p class="subtitle" style="margin-top: 24px;">System entries (read-only)</p>
    <div class="card">${rows || `<div class="empty">No system entries.</div>`}</div>`;
}

async function refreshHosts(): Promise<void> {
  const listEl = document.querySelector<HTMLDivElement>("#h-list")!;
  const entries = await ListHosts();
  if (!entries.length) {
    listEl.innerHTML = `<div class="empty">No managed entries yet.</div>`;
    return;
  }
  listEl.innerHTML = "";
  for (const e of entries) {
    const row = document.createElement("div");
    row.className = "row";
    row.innerHTML = `
      <span class="primary mono">${escapeHtml(e.hostname)}</span>
      <span class="secondary mono">${escapeHtml(e.ip)}</span>
      ${e.comment ? `<span class="badge">${escapeHtml(e.comment)}</span>` : ``}
      <span class="spacer"></span>`;
    const btn = document.createElement("button");
    btn.className = "btn danger";
    btn.textContent = "Remove";
    btn.addEventListener("click", async () => {
      if (getConfirmRemove()) {
        const ok = await confirmDialog("Remove entry", `Remove the managed entry for ${e.hostname}?`);
        if (!ok) return;
      }
      await RemoveHost(e.hostname);
      await refreshHosts();
    });
    row.appendChild(btn);
    listEl.appendChild(row);
  }
}

async function addHost(): Promise<void> {
  const errEl = document.querySelector<HTMLParagraphElement>("#h-error")!;
  errEl.textContent = "";
  const hostname = document.querySelector<HTMLInputElement>("#h-hostname")!.value.trim();
  const ip = document.querySelector<HTMLInputElement>("#h-ip")!.value.trim();
  const comment = document.querySelector<HTMLInputElement>("#h-comment")!.value.trim();
  try {
    await AddHost(new hosts.Entry({ hostname, ip, comment: comment || undefined }));
    document.querySelector<HTMLInputElement>("#h-hostname")!.value = "";
    document.querySelector<HTMLInputElement>("#h-ip")!.value = "";
    document.querySelector<HTMLInputElement>("#h-comment")!.value = "";
    await refreshHosts();
  } catch (err) {
    // Errors from the Go layer (validation, helper not installed, etc.).
    errEl.textContent = String(err);
  }
}

// --- Settings ---

function renderSettings(): void {
  const currentTheme = getTheme();
  const currentFont = getFont();

  const toggle = (id: string, checked: boolean) =>
    `<label class="switch"><input type="checkbox" id="${id}" ${checked ? "checked" : ""}><span class="slider"></span></label>`;

  const themeOpt = (value: Theme, label: string) =>
    `<button data-theme="${value}" class="${value === currentTheme ? "active" : ""}">${label}</button>`;

  const fontTile = (value: Font, label: string) =>
    `<button class="font-tile ${value === currentFont ? "active" : ""}" data-font="${value}"
       style="font-family: ${FONT_STACKS[value]}">
       <div class="font-sample">Aa</div>
       <div class="font-sample-sub">127.0.0.1 · app.local</div>
       <div class="font-name">${label}</div>
     </button>`;

  content.innerHTML = `
    <h1>Settings</h1>
    <p class="subtitle">Preferences</p>
    <div class="card">
      <div class="row">
        <span class="primary">Appearance</span>
        <span class="secondary">Theme used by the dnsctl window</span>
        <span class="spacer"></span>
        <div class="segmented" id="theme-seg">
          ${themeOpt("light", "Light")}${themeOpt("dark", "Dark")}${themeOpt("system", "System")}
        </div>
      </div>
      <div class="field">
        <span class="field-label">Font</span>
        <div class="font-grid" id="font-grid">
          ${fontTile("system", "System")}${fontTile("rounded", "Rounded")}${fontTile("mono", "Mono")}
        </div>
      </div>
    </div>

    <p class="subtitle" style="margin-top: 20px;">Hosts</p>
    <div class="card">
      <div class="row">
        <span class="primary">Show system entries</span>
        <span class="secondary">Display the read-only /etc/hosts lines dnsctl doesn't manage</span>
        <span class="spacer"></span>
        ${toggle("opt-showsys", getShowSystem())}
      </div>
      <div class="row">
        <span class="primary">Confirm before removing</span>
        <span class="secondary">Ask before deleting a managed entry</span>
        <span class="spacer"></span>
        ${toggle("opt-confirm", getConfirmRemove())}
      </div>
    </div>

    <p class="subtitle" style="margin-top: 20px;">Helper</p>
    <div class="card">
      <div class="row">
        <span class="primary">dnsctl-helper</span>
        <span class="secondary">Performs privileged DNS / hosts changes</span>
        <span class="spacer"></span>
        <span id="helper-status"><span class="badge">Checking…</span></span>
      </div>
      <div id="helper-detail"></div>
    </div>`;

  const seg = document.querySelector<HTMLDivElement>("#theme-seg")!;
  seg.querySelectorAll<HTMLButtonElement>("button").forEach((btn) => {
    btn.addEventListener("click", () => {
      applyTheme(btn.dataset.theme as Theme);
      seg.querySelectorAll("button").forEach((b) => b.classList.toggle("active", b === btn));
    });
  });

  const grid = document.querySelector<HTMLDivElement>("#font-grid")!;
  grid.querySelectorAll<HTMLButtonElement>(".font-tile").forEach((tile) => {
    tile.addEventListener("click", () => {
      applyFont(tile.dataset.font as Font);
      grid.querySelectorAll(".font-tile").forEach((t) => t.classList.toggle("active", t === tile));
    });
  });

  document
    .querySelector<HTMLInputElement>("#opt-showsys")!
    .addEventListener("change", (e) => setShowSystem((e.target as HTMLInputElement).checked));
  document
    .querySelector<HTMLInputElement>("#opt-confirm")!
    .addEventListener("change", (e) => setConfirmRemove((e.target as HTMLInputElement).checked));

  void refreshHelperStatus();
}

// refreshHelperStatus probes the helper and fills the Settings diagnostics row.
async function refreshHelperStatus(): Promise<void> {
  const statusEl = document.querySelector<HTMLSpanElement>("#helper-status");
  const detailEl = document.querySelector<HTMLDivElement>("#helper-detail");
  if (!statusEl || !detailEl) return;
  const st = await HelperStatus();
  if (st.reachable) {
    statusEl.innerHTML = `<span class="badge active">Connected</span>`;
    detailEl.innerHTML = "";
    return;
  }
  statusEl.innerHTML = `<span class="badge danger-badge">Not reachable</span>`;
  detailEl.innerHTML = `
    <div class="row"><span class="secondary">${escapeHtml(st.detail)}</span></div>
    <div class="row"><span class="secondary">Install it from the repo:&nbsp;<span class="mono">sudo make install-helper</span></span></div>`;
}

setView("dns");
